#include <stdio.h>
#include <stdlib.h>

typedef struct {int start; int end;} Interval;
int cmp(const void *a, const void *b) {
    const Interval *ia = (const Interval *)a;
    const Interval *ib = (const Interval *)b;
    if (ia->end != ib->end) return ia->end - ib->end;
    return ia->start - ib->start;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        Interval *arr = (Interval*)malloc(N * sizeof(Interval));
        for(int i=0;i<N;i++){
            int S,D; scanf("%d %d", &S, &D);
            arr[i].start = S;
            arr[i].end = S + D - 1;
        }
        qsort(arr, N, sizeof(Interval), cmp);
        int cnt = 0;
        long long last_end = -1000000000LL; // sufficiently small
        for(int i=0;i<N;i++){
            if(arr[i].start >= last_end + 2){
                cnt++;
                last_end = arr[i].end;
            }
        }
        printf("%d\n", cnt);
        free(arr);
    }
    return 0;
}

