            int S,D; cin>>S>>D;
            ev[i].start = S;
            ev[i].end = S + D - 1;
        }
        sort(ev.begin(), ev.end(), [](const Event& a, const Event& b){
            if(a.end!=b.end) return a.end<b.end;
            return a.start<b.start;
        });
        int cnt=0; long long last_end = -4e18;
        for(const auto &e: ev){
            if(e.start >= last_end + 2){
                ++cnt;
                last_end = e.end;
            }
        }
        cout<<cnt<<"\n";
    }
    return 0;
}

