import java.io.*;
import java.util.*;
public class Main {
    static class Event{int start, end; Event(int s,int e){start=s; end=e;}}
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = fs.nextInt();
            Event[] ev = new Event[N];
            for(int i=0;i<N;i++){
                int S = fs.nextInt();
                int D = fs.nextInt();
                ev[i] = new Event(S, S + D - 1);
            }
            Arrays.sort(ev, (a,b) -> a.end != b.end ? a.end - b.end : a.start - b.start);
            int cnt = 0;
            long lastEnd = Long.MIN_VALUE/4;
            for(Event e: ev){
                if(e.start >= lastEnd + 2){
                    cnt++;
                    lastEnd = e.end;
                }
            }
            sb.append(cnt).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if(ptr >= len){
                len = in.read(buffer);
                ptr = 0;
                if(len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while(c <= ' ' && c != -1);
            if(c == '-') { sign = -1; c = readByte(); }
            while(c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

